INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Accompagnement commercial & coaching', 'Formation sur la structuration d’une direction commerciale et coaching des équipes.', 365, 9250000.00, 'entreprise', '2026-07-10', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Structurer une direction commerciale performante\n• Développer une stratégie commerciale cohérente et orientée résultats\n• Accompagner et coacher les équipes vers la performance\n• Mettre en place des outils de suivi et de reporting efficaces\n• Optimiser les processus commerciaux et la force de vente\n• Favoriser une culture commerciale orientée client et performance\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre les enjeux et responsabilités d’une direction commerciale, concevoir et structurer une organisation commerciale adaptée, accompagner et coacher les équipes vers la performance, mettre en place des outils de suivi et KPI, et développer une stratégie commerciale cohérente et orientée résultats.\n\n--- PRÉREQUIS ---\nExpérience préalable en management ou gestion commerciale souhaitée. Connaissances de base en stratégie et organisation d’entreprise.\n\n--- CONTENU ---\nModule 1 : Fondamentaux d’une direction commerciale\nModule 2 : Élaboration de la stratégie commerciale\nModule 3 : Structuration de la force de vente\nModule 4 : Accompagnement et coaching commercial\nModule 5 : Outils de pilotage et KPI\nModule 6 : Processus commerciaux et optimisation\nModule 7 : Gestion du changement et culture commerciale\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nDirecteurs commerciaux, responsables de vente, chefs d’équipe, consultants en stratégie commerciale, managers en charge de structurer ou réorganiser la fonction commerciale.\n\n--- MÉTHODES ---\nApports théoriques interactifs, études de cas sectoriels, ateliers pratiques, simulations de terrain, jeux de rôle, coaching individuel, supports pédagogiques (slides, guides pratiques, outils CRM).\n\n--- SUPPORTS ---\nOutils CRM, logiciels de reporting commercial, tableaux de bord digitaux, études de cas, supports PDF, modèles pratiques et guides de structuration commerciale.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
